SELECT
r.*,
u.nick_name AS nickName,
l.lab_name AS labName,
t.nick_name AS teacherNickName
FROM reservation r
LEFT JOIN sys_user u ON r.user_id = u.user_id
LEFT JOIN labs l ON r.lab_id = l.id
LEFT JOIN sys_user t ON r.teacher_id = t.user_id


     and r.user_id = #{userId}
     and r.lab_id = #{labId}
     and r.status = #{status}
     and r.teacher_id = #{teacherId}



        AND DATE(r.reservation_date) >= #{beginReservationDate}


        AND DATE(r.reservation_date) <= #{endReservationDate}

